456:     private void handleTasksWithoutStateUpdater(final Map<TaskId, Set<TopicPartition>> activeTasksToCreate,
457:                                                 final Map<TaskId, Set<TopicPartition>> standbyTasksToCreate,
458:                                                 final Map<Task, Set<TopicPartition>> tasksToRecycle,
459:                                                 final Set<Task> tasksToCloseClean) {
460:         for (final Task task : tasks.allTasks()) {
461:             final TaskId taskId = task.id();
462:             if (activeTasksToCreate.containsKey(taskId)) {
463:                 if (task.isActive()) {
464:                     final Set<TopicPartition> topicPartitions = activeTasksToCreate.get(taskId);
465:                     if (tasks.updateActiveTaskInputPartitions(task, topicPartitions)) {
466:                         task.updateInputPartitions(topicPartitions, topologyMetadata.nodeToSourceTopics(task.id()));
467:                     }
468:                     task.resume();
469:                 } else {
470:                     tasksToRecycle.put(task, activeTasksToCreate.get(taskId));
471:                 }
472:                 activeTasksToCreate.remove(taskId);
473:             } else if (standbyTasksToCreate.containsKey(taskId)) {
474:                 if (!task.isActive()) {
475:                     updateInputPartitionsOfStandbyTaskIfTheyChanged(task, standbyTasksToCreate.get(taskId));
476:                     task.resume();
477:                 } else {
478:                     tasksToRecycle.put(task, standbyTasksToCreate.get(taskId));
479:                 }
480:                 standbyTasksToCreate.remove(taskId);
481:             } else {
482:                 tasksToCloseClean.add(task);
483:             }
484:         }
485:     }
